import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"38. Shift Work Allowance","description":"","frontmatter":{"title":"38. Shift Work Allowance","eba":"Allied Health Professionals 2021-2026","topics":["hours","shift-work","rosters","allowances"]},"headers":[],"relativePath":"ebas/allied-health/allowances/38-shift-work-allowance.md","filePath":"ebas/allied-health/allowances/38-shift-work-allowance.md"}'),r={name:"ebas/allied-health/allowances/38-shift-work-allowance.md"};function l(s,e,i,h,d,c){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_38-shift-work-allowance" tabindex="-1">38. Shift Work Allowance <a class="header-anchor" href="#_38-shift-work-allowance" aria-label="Permalink to &quot;38. Shift Work Allowance&quot;">​</a></h1><p><strong>38.1</strong> In addition to any other rates prescribed elsewhere in the Agreement, an Employee whose rostered hours of ordinary duty finish between 6.00 p.m. and</p><p><strong>8.00</strong> a.m. or commence between 6.00 p.m. and 6.30 a.m. will be paid the amount specified in <a href="/eba/ebas/allied-health/appendices/3-allowances-and-top-of-band-payments.html">Appendix 3</a> per rostered period of duty. Note: The current shift work allowance rates in <a href="/eba/ebas/allied-health/appendices/3-allowances-and-top-of-band-payments.html">Appendix 3</a>, before any increases were applied, were calculated as 2.5% of the weekly wage of the rate applicable to first year of experience after qualifications in the 2020 Agreement, save that some shift allowances as per subclauses 38.1(a)-(g) of the 2020 Agreement were higher.</p><p><strong>38.2</strong> Provided that in the case of an Employee working on any rostered hours of ordinary duty finishing on the day after commencing duty or commencing after midnight and before 5.00 a.m. they will be paid for any such period of duty the amount specified in <a href="/eba/ebas/allied-health/appendices/3-allowances-and-top-of-band-payments.html">Appendix 3</a> for ‘night shift’.</p><p><strong>38.3</strong> The allowances payable pursuant to this clause 38 will be calculated to the nearest five (5) cents, portions of a cent being disregarded.</p>',5)])])}const w=a(r,[["render",l]]);export{f as __pageData,w as default};
